// src/pages/Auth/LoginPage.jsx
import { useState, useEffect } from "react";
import { T } from "../../assets/styles/theme";
import { Btn, Modal, Input, Select } from "../../components/UI";
import { login, registerUser, getActiveDepartments } from "../../api/auth";

// ─── ROLE LOGIN CARDS ─────────────────────────────────────────────────────────
const ROLES = [
  { key: "student", icon: "👨‍🎓", label: "Student", sub: "Access courses, assignments & performance",  color: T.accent,  bg: "linear-gradient(135deg,#011F2B,#02485E)" },
  { key: "teacher", icon: "👨‍🏫", label: "Teacher", sub: "Manage courses, students & classes",        color: T.accentG, bg: "linear-gradient(135deg,#001A0E,#01321A)" },
  { key: "parent",  icon: "👨‍👩‍👦", label: "Parent",  sub: "Track your child's progress & fees",        color: T.accentR, bg: "linear-gradient(135deg,#1A0005,#2D0010)" },
  { key: "admin",   icon: "🛡️",  label: "Admin",   sub: "Full system control & analytics",            color: T.accentY, bg: "linear-gradient(135deg,#1A1200,#2D2000)" },
];

// ─── REGISTRATION MODAL ───────────────────────────────────────────────────────
const RegModal = ({ role, onClose, onSuccess }) => {
  const [form, setForm]   = useState({});
  const [depts, setDepts] = useState([]);
  const [loading, setLoading] = useState(false);

  // Fetch departments once — needed for student and teacher registration
  useEffect(() => {
    if (role === "student" || role === "teacher") {
      getActiveDepartments().then(d => setDepts(Array.isArray(d) ? d : [])).catch(console.error);
    }
  }, [role]);

  const f = (key) => form[key] || "";
  const set = (key) => (e) => setForm(prev => ({ ...prev, [key]: e.target.value }));

  const handleSubmit = async () => {
    const password = f("password");
    const confirm  = f("confirm");
    if (password !== confirm) { alert("Passwords do not match!"); return; }
    if (password.length < 8)  { alert("Password must be at least 8 characters."); return; }

    const base = {
      name:     f("name"),
      email:    f("email"),
      password,
      role: role.toUpperCase(),
    };

    let extra = {};
    if (role === "student" || role === "teacher") {
      extra = { department: f("department"), gender: f("gender") || null, phone: f("phone") || null };
    }
    if (role === "teacher") {
      extra = { ...extra, qualification: f("qualification") || null };
    }
    if (role === "admin") {
      extra = { academyName: f("academyName"), gender: f("gender") || null };
    }

    try {
      setLoading(true);
      const auth = await registerUser({ ...base, ...extra });
      onSuccess(auth);
    } catch (err) {
      alert(err.message || "Registration failed");
    } finally {
      setLoading(false);
    }
  };

  const title = role.charAt(0).toUpperCase() + role.slice(1) + " Registration";

  return (
    <Modal open title={title} onClose={onClose}>
      <p style={{ fontSize: 12, color: T.muted, marginBottom: 16 }}>
        {role === "admin"
          ? "⚠️ Admin registration requires a valid referral from an existing Super Admin."
          : "Create your account to get started."}
      </p>

      {/* Auto-generated ID field (display only) */}
     <Input
  label="ID (Auto-generated)"
  value={generatedId}
  placeholder="AUTO-GENERATED BY SYSTEM"
  disabled
/>

      {/* Name */}
      <Input
        label={`${title.replace(" Registration", "")} Name *`}
        value={f("name")} onChange={set("name")}
        placeholder="Full name"
      />

      {/* Admin extra */}
      {role === "admin" && (
        <Input label="Academy Name *" value={f("academyName")} onChange={set("academyName")} placeholder="Academy / Institute name" />
      )}

      {/* Teacher extra */}
      {role === "teacher" && (
        <Input label="Qualification" value={f("qualification")} onChange={set("qualification")} placeholder="e.g. M.Tech, PhD" />
      )}

      {/* Department — dynamic from backend */}
      {(role === "student" || role === "teacher") && (
        <Select
          label="Department *"
          value={f("department")}
          onChange={set("department")}
          options={[
            { value: "", label: depts.length === 0 ? "Loading departments…" : "-- Select Department --" },
            ...depts.map(d => ({ value: d.name, label: d.name })),
          ]}
        />
      )}

      {/* Gender */}
      {(role === "student" || role === "teacher" || role === "admin") && (
        <Select label="Gender" value={f("gender")} onChange={set("gender")}
          options={[
            { value: "", label: "Select Gender" },
            { value: "Male", label: "Male" },
            { value: "Female", label: "Female" },
            { value: "Other", label: "Other" },
          ]}
        />
      )}

      {/* Email + Password */}
      <Input label="Email Address *" type="email" value={f("email")} onChange={set("email")} placeholder={`${role}@email.com`} />
      <Input label="Password *" type="password" value={f("password")} onChange={set("password")} placeholder="Min 8 characters" />
      <Input label="Confirm Password *" type="password" value={f("confirm")} onChange={set("confirm")} placeholder="Repeat password" />

      <Btn variant="primary" full size="lg" onClick={handleSubmit} disabled={loading}>
        {loading ? "Creating account…" : "Create Account →"}
      </Btn>
    </Modal>
  );
};

// ─── LOGIN PAGE ───────────────────────────────────────────────────────────────
const LoginPage = ({ onLoginSuccess, onBack }) => {
  const [zoomed, setZoomed]         = useState(null);
  const [modal, setModal]           = useState(null);
  const [loadingRole, setLoadingRole] = useState(null);
  const [credentials, setCredentials] = useState({
    student: { email: "", password: "" },
    teacher: { email: "", password: "" },
    parent:  { email: "", password: "" },
    admin:   { email: "", password: "" },
  });

  const handleFieldChange = (roleKey, field) => (e) => {
    setCredentials(prev => ({ ...prev, [roleKey]: { ...prev[roleKey], [field]: e.target.value } }));
  };

  const handleLoginClick = async (roleKey) => {
    const { email, password } = credentials[roleKey];
    if (!email || !password) { alert("Enter email and password."); return; }
    try {
      setLoadingRole(roleKey);
      const auth = await login(email, password, roleKey);
      onLoginSuccess(auth);
    } catch (err) {
      alert(err.message || "Login failed");
    } finally {
      setLoadingRole(null);
    }
  };

  return (
    <div style={{ minHeight: "100vh", background: T.bg, display: "flex", flexDirection: "column" }}>
      {/* Header */}
      <div style={{ padding: "0 40px", height: 64, display: "flex", alignItems: "center", justifyContent: "space-between", borderBottom: `1px solid ${T.border}`, background: "rgba(6,4,15,.8)", backdropFilter: "blur(20px)" }}>
        <div style={{ fontFamily: "Syne", fontSize: 18, fontWeight: 900, display: "flex", alignItems: "center", gap: 10 }}>
          <div style={{ width: 32, height: 32, background: `linear-gradient(135deg, ${T.primary}, ${T.accent})`, borderRadius: 8, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14 }}>🎓</div>
          Zenelait<span style={{ color: T.accent }}>InfoTech</span>
        </div>
        <Btn variant="ghost" size="sm" onClick={onBack}>← Back to Website</Btn>
      </div>

      {/* Content */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "40px 20px", background: `radial-gradient(ellipse 80% 80% at 50% 50%, rgba(124,58,237,.12), transparent 70%)` }}>
        <div style={{ textAlign: "center", marginBottom: 44 }}>
          <div style={{ fontFamily: "Syne", fontSize: "clamp(26px,4vw,42px)", fontWeight: 900, marginBottom: 8 }}>
            Welcome to <span style={{ color: T.accent }}>Zenelait</span> LMS
          </div>
          <p style={{ color: T.muted, fontSize: 14 }}>Hover over your role and sign in to continue</p>
        </div>

        {/* 4 Role Cards */}
        <div style={{ display: "flex", gap: 18, width: "100%", maxWidth: 1100 }}>
          {ROLES.map(role => {
            const isZoomed = zoomed === role.key;
            const isShrunk = zoomed && zoomed !== role.key;
            return (
              <div key={role.key}
                style={{
                  flex: isZoomed ? 2.4 : isShrunk ? 0.55 : 1,
                  minHeight: 420, borderRadius: 20, overflow: "hidden", cursor: "pointer",
                  border: `1px solid ${isZoomed ? role.color : T.border}`,
                  transition: "all .45s cubic-bezier(.4,0,.2,1)",
                  background: role.bg,
                  boxShadow: isZoomed ? `0 30px 80px rgba(0,0,0,.5), 0 0 40px ${role.color}30` : "none",
                  opacity: isShrunk ? 0.55 : 1,
                }}
                onMouseEnter={() => setZoomed(role.key)}
                onMouseLeave={() => setZoomed(null)}
              >
                <div style={{ position: "relative", zIndex: 1, padding: "28px 24px", height: "100%", display: "flex", flexDirection: "column" }}>
                  <div style={{ width: 60, height: 60, borderRadius: 16, background: `${role.color}25`, border: `1.5px solid ${role.color}40`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 28, marginBottom: 16, transform: isZoomed ? "scale(1.12)" : "scale(1)", transition: "transform .3s" }}>
                    {role.icon}
                  </div>
                  <h3 style={{ fontFamily: "Syne", fontSize: 22, fontWeight: 800, marginBottom: 6, color: "#fff" }}>{role.label}</h3>
                  <p style={{ fontSize: 13, color: "rgba(255,255,255,.55)", lineHeight: 1.5 }}>{role.sub}</p>

                  {isZoomed && (
                    <div style={{ marginTop: 24, animation: "fadeUp .35s ease" }}>
                      <div style={{ marginBottom: 12 }}>
                        <input type="email" placeholder={`${role.label.toLowerCase()}@email.com`}
                          value={credentials[role.key].email}
                          onChange={handleFieldChange(role.key, "email")}
                          style={{ width: "100%", background: "rgba(255,255,255,.08)", border: "1.5px solid rgba(255,255,255,.15)", borderRadius: 9, padding: "10px 14px", fontSize: 13, color: "#fff", outline: "none", fontFamily: "DM Sans" }}
                          onFocus={e => e.target.style.borderColor = role.color}
                          onBlur={e => e.target.style.borderColor = "rgba(255,255,255,.15)"}
                        />
                      </div>
                      <div style={{ marginBottom: 16 }}>
                        <input type="password" placeholder="Password"
                          value={credentials[role.key].password}
                          onChange={handleFieldChange(role.key, "password")}
                          style={{ width: "100%", background: "rgba(255,255,255,.08)", border: "1.5px solid rgba(255,255,255,.15)", borderRadius: 9, padding: "10px 14px", fontSize: 13, color: "#fff", outline: "none", fontFamily: "DM Sans" }}
                          onFocus={e => e.target.style.borderColor = role.color}
                          onBlur={e => e.target.style.borderColor = "rgba(255,255,255,.15)"}
                        />
                      </div>
                      <button
                        onClick={() => handleLoginClick(role.key)}
                        disabled={loadingRole === role.key}
                        style={{ width: "100%", background: `linear-gradient(135deg, ${role.color}, ${role.color}CC)`, border: "none", color: (role.key === "admin" || role.key === "parent") ? "#000" : "#fff", padding: "12px", borderRadius: 9, fontWeight: 800, fontSize: 14, cursor: "pointer", marginBottom: 12, fontFamily: "DM Sans", opacity: loadingRole === role.key ? 0.7 : 1 }}
                      >
                        {loadingRole === role.key ? "Logging in…" : `Login as ${role.label} →`}
                      </button>
                      <button
                        onClick={() => setModal(role.key)}
                        style={{ width: "100%", background: "rgba(255,255,255,.06)", border: "1px solid rgba(255,255,255,.15)", color: "rgba(255,255,255,.6)", padding: "9px", borderRadius: 9, fontSize: 12, cursor: "pointer", fontFamily: "DM Sans" }}
                      >
                        New {role.label}? Register here
                      </button>
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        <div style={{ display: "flex", gap: 24, marginTop: 28, flexWrap: "wrap", justifyContent: "center" }}>
          {["← Back to Website", "Forgot Password?", "Need Help?", "Privacy Policy"].map(l => (
            <button key={l} onClick={l === "← Back to Website" ? onBack : undefined}
              style={{ background: "none", border: "none", color: T.muted, fontSize: 13, cursor: "pointer" }}
            >{l}</button>
          ))}
        </div>
      </div>

      {/* Registration Modal */}
      {modal && (
        <RegModal role={modal} onClose={() => setModal(null)}
          onSuccess={(auth) => { setModal(null); onLoginSuccess(auth); }} />
      )}
    </div>
  );
};

export default LoginPage;
